/** @brief Function to compute cardinality. */
template <typename T>
auto HyperLogLogPresto<T>::ComputeCardinality() -> void {
  if (n_bits_ <= 0) {
    cardinality_ = 0;
    return;
  }

  // Sum of 2^(-register_value) for all registers
  double sum = 0.0;
  for (uint32_t i = 0; i < num_registers_; ++i) {
    // Reconstruct the register value from dense and overflow buckets
    uint64_t dense_value = dense_bucket_[i].to_ullong();
    uint64_t overflow_value = 0;
    if (overflow_bucket_.count(i) > 0) {
      overflow_value = overflow_bucket_[i].to_ullong();
    }

    // Reconstruct: full_value = (overflow_value << 4) | dense_value
    uint64_t register_value = (overflow_value << 4) | dense_value;

    // Handle the case where register_value is 0 (no elements hashed to this register)
    if (register_value == 0) {
      register_value = 1;
    }

    sum += std::pow(2.0, -static_cast<double>(register_value));
  }

  // Cardinality estimation: α * m² / sum
  double m = static_cast<double>(num_registers_);
  cardinality_ = static_cast<uint64_t>(CONSTANT * m * m / sum);
}

