/** @brief Element is added for HLL calculation. */
template <typename KeyType>
auto HyperLogLogPresto<KeyType>::AddElem(KeyType val) -> void {
  if (n_bits_ <= 0) {
    return;
  }

  hash_t hash = CalculateHash(val);

  // Extract the register index from the first n_bits bits
  uint32_t register_idx = hash & ((1U << n_bits_) - 1);  // Lower n_bits bits

  // Get the remaining bits (shift out the first n_bits)
  hash_t remaining_bits = hash >> n_bits_;

  // Count leading zeros + 1 in the remaining (64-n_bits) bits
  uint64_t leading_zero_count;
  if (remaining_bits == 0) {
    leading_zero_count = (64 - n_bits_) + 1;  // All remaining bits are zero
  } else {
    // Count leading zeros using __builtin_clzll
    // __builtin_clzll counts in a 64-bit value, but we have (64-n_bits) bits of actual data
    // The top n_bits are padding zeros from the shift, so we need to subtract them
    uint64_t lz_in_64bit = __builtin_clzll(remaining_bits);
    uint64_t lz_in_actual_bits = lz_in_64bit - n_bits_;
    leading_zero_count = lz_in_actual_bits + 1;
  }

  // Presto encoding: split the value into dense (4-bit) and overflow (3-bit) parts
  // Dense bucket stores the lower 4 bits (0-15)
  // Overflow bucket stores the upper 3 bits (0-7)
  uint8_t dense_value = leading_zero_count & 0x0F;  // Lower 4 bits
  uint8_t overflow_value = (leading_zero_count >> 4) & 0x07;  // Upper 3 bits (shift right 4 to get bits 4-6)

  // Update dense bucket
  std::bitset<DENSE_BUCKET_SIZE> current_dense = dense_bucket_[register_idx];
  std::bitset<DENSE_BUCKET_SIZE> new_dense(dense_value);

  if (new_dense.to_ullong() > current_dense.to_ullong()) {
    dense_bucket_[register_idx] = new_dense;
  }

  // Update overflow bucket
  std::bitset<OVERFLOW_BUCKET_SIZE> current_overflow(0);
  if (overflow_bucket_.count(register_idx) > 0) {
    current_overflow = overflow_bucket_[register_idx];
  }
  std::bitset<OVERFLOW_BUCKET_SIZE> new_overflow(overflow_value);

  if (new_overflow.to_ullong() > current_overflow.to_ullong()) {
    overflow_bucket_[register_idx] = new_overflow;
  }
}

