#include "primer/hyperloglog_presto.h"

namespace bustub {

/** @brief Parameterized constructor. */
template <typename KeyType>
HyperLogLogPresto<KeyType>::HyperLogLogPresto(int16_t n_leading_bits) : cardinality_(0), n_bits_(n_leading_bits) {
  if (n_bits_ <= 0) {
    num_registers_ = 0;
  } else {
    num_registers_ = 1U << n_bits_;  // 2^n_bits
    dense_bucket_.assign(num_registers_, 0);
  }
}

/** @brief Element is added for HLL calculation. */
template <typename KeyType>
auto HyperLogLogPresto<KeyType>::AddElem(KeyType val) -> void {
  if (n_bits_ <= 0) {
    return;
  }

  hash_t hash = CalculateHash(val);

  // Extract the register index from the first n_bits bits
  uint32_t register_idx = hash & ((1U << n_bits_) - 1);  // Lower n_bits bits

  // Get the remaining bits (shift out the first n_bits)
  hash_t remaining_bits = hash >> n_bits_;

  // Find the position of the first 1 bit (counting from 1 on the right)
  // This is equivalent to: 64 - leading_zeros
  uint64_t rho;
  if (remaining_bits == 0) {
    rho = 64 - n_bits_;  // All remaining bits are zero
  } else {
    // Count leading zeros using __builtin_clzll and compute position
    rho = 64 - __builtin_clzll(remaining_bits);
  }

  // Presto encoding: split the rho value into dense (4-bit) and overflow (3-bit) parts
  // Dense bucket stores the lower 4 bits (0-15)
  // Overflow bucket stores the upper bits (0-7)
  uint8_t dense_value = rho & 0x0F;  // Lower 4 bits
  uint8_t overflow_value = (rho >> 4) & 0x07;  // Upper 3 bits

  // Update dense bucket
  std::bitset<DENSE_BUCKET_SIZE> current_dense = dense_bucket_[register_idx];
  std::bitset<DENSE_BUCKET_SIZE> new_dense(dense_value);

  if (new_dense.to_ullong() > current_dense.to_ullong()) {
    dense_bucket_[register_idx] = new_dense;
  }

  // Update overflow bucket
  std::bitset<OVERFLOW_BUCKET_SIZE> current_overflow(0);
  if (overflow_bucket_.count(register_idx) > 0) {
    current_overflow = overflow_bucket_[register_idx];
  }
  std::bitset<OVERFLOW_BUCKET_SIZE> new_overflow(overflow_value);

  if (new_overflow.to_ullong() > current_overflow.to_ullong()) {
    overflow_bucket_[register_idx] = new_overflow;
  }
}

/** @brief Function to compute cardinality. */
template <typename T>
auto HyperLogLogPresto<T>::ComputeCardinality() -> void {
  if (n_bits_ <= 0) {
    cardinality_ = 0;
    return;
  }

  // Sum of 2^(-register_value) for all registers
  double sum = 0.0;
  for (uint32_t i = 0; i < num_registers_; ++i) {
    // Reconstruct the rho value from dense and overflow buckets
    // rho = (overflow_value << 4) | dense_value
    uint64_t dense_value = dense_bucket_[i].to_ullong();
    uint64_t overflow_value = 0;
    if (overflow_bucket_.count(i) > 0) {
      overflow_value = overflow_bucket_[i].to_ullong();
    }

    // Reconstruct: rho = (overflow_value << 4) | dense_value
    uint64_t rho = (overflow_value << 4) | dense_value;

    // If rho is 0 (no elements hashed to this register), treat it as 0
    // which means 2^-0 = 1 in the sum
    sum += std::pow(2.0, -static_cast<double>(rho));
  }

  // Cardinality estimation: α * m² / sum
  double m = static_cast<double>(num_registers_);
  cardinality_ = static_cast<uint64_t>(CONSTANT * m * m / sum);
}

