  std::bitset<DENSE_BUCKET_SIZE> current_dense = dense_bucket_[register_idx];
  std::bitset<DENSE_BUCKET_SIZE> new_dense(dense_value);

  if (new_dense.to_ullong() > current_dense.to_ullong()) {
    dense_bucket_[register_idx] = new_dense;
