  } else {
    // Count leading zeros using __builtin_clzll and compute position
    rho = 64 - __builtin_clzll(remaining_bits);
  }

  // Presto encoding: split the rho value into dense (4-bit) and overflow (3-bit) parts
  // Dense bucket stores the lower 4 bits (0-15)
  // Overflow bucket stores the upper bits (0-7)
  uint8_t dense_value = rho & 0x0F;  // Lower 4 bits
  uint8_t overflow_value = (rho >> 4) & 0x07;  // Upper 3 bits

  // Update dense bucket
  std::bitset<DENSE_BUCKET_SIZE> current_dense = dense_bucket_[register_idx];
  std::bitset<DENSE_BUCKET_SIZE> new_dense(dense_value);

  if (new_dense.to_ullong() > current_dense.to_ullong()) {
    dense_bucket_[register_idx] = new_dense;
  }

  // Update overflow bucket
  std::bitset<OVERFLOW_BUCKET_SIZE> new_overflow(overflow_value);
  auto it = overflow_bucket_.find(register_idx);
  if (it == overflow_bucket_.end() || new_overflow.to_ullong() > it->second.to_ullong()) {
    overflow_bucket_[register_idx] = new_overflow;
  }
